    "content": "/**
 * @file kcp_wrapper.h
 * @brief KCP协议封装
 * 
 * 本文件提供KCP协议的C++封装，用于快速可靠传输。
 * KCP是一种基于UDP的ARQ协议，具有低延迟和高可靠性的特点。
 * 
 * 特性：
 * - 不可靠UDP上的可靠传输
 * - 可配置的重传延迟
 * - 流量控制和拥塞控制
 * - 低延迟优化
 */

#pragma once

#include <cstdint>
#include <cstddef>
#include <functional>
#include <memory>
#include <string>

namespace PhysicsSync {

// =====================================================================
// KCP回调类型
// =====================================================================

/**
 * @brief 发送回调函数类型
 * 
 * 当需要发送数据时，KCP会调用此函数。
 * @param buffer 要发送的数据缓冲区
 * @param size 数据大小
 * @param user 用户自定义指针
 */
typedef void (*kcp_send_to_net_func)(const void* buffer, int size, void* user);

/**
 * @brief 日志回调函数类型
 * @param level 日志级别
 * @param message 消息内容
 */
typedef void (*kcp_log_func)(int level, const char* message);

// =====================================================================
// KCP配置
// =====================================================================

/**
 * @brief KCP配置结构体
 */
struct KCPConfig {
    uint32_t conv;                ///< 会话ID（用于多路复用）
    uint32_t mtu;                 ///< 最大传输单元（默认1400字节）
    int fastresend;               ///< 快速重传阈值（0表示禁用）
    int nodelay;                  ///< 无模式标志
    int interval;                 ///< 内部更新间隔（毫秒）
    int rcvwnd;                   ///< 接收窗口大小
    int sndwnd;                   ///< 发送窗口大小
    uint32_t rto_min;             ///< 最小RTO（毫秒）

    /**
     * @brief 默认配置
     */
    KCPConfig()
        : conv(0)
        , mtu(1400)
        , fastresend(0)
        , nodelay(0)
        , interval(10)
        , rcvwnd(128)
        , sndwnd(128)
        , rto_min(100)
    {}
};

/**
 * @brief 无模式配置（优化延迟）
 * 
 * 启用后KCP会禁用拥塞控制，以获得最低延迟。
 * 适合对延迟敏感的应用，如实时物理同步。
 */
inline KCPConfig GetNodelayConfig(uint32_t conv = 0) {
    KCPConfig config;
    config.conv = conv;
    config.nodelay = 1;       // 启用无模式
    config.interval = 10;     // 10ms内部更新
    config.rto_min = 50;      // 50ms最小RTO
    return config;
}

/**
 * @brief 标准配置（平衡延迟和可靠性）
 */
inline KCPConfig GetStandardConfig(uint32_t conv = 0) {
    KCPConfig config;
    config.conv = conv;
    config.nodelay = 0;
    config.interval = 10;
    config.rto_min = 100;
    return config;
}

// =====================================================================
// IKCPOutput - 输出接口
// =====================================================================

/**
 * @brief KCP输出接口
 * 
 * 实现此接口以处理KCP的输出数据。
 */
class IKCPOutput {
public:
    virtual ~IKCPOutput() = default;

    /**
     * @brief 输出数据
     * @param buffer 数据缓冲区
     * @param size 数据大小
     * @return 0表示成功，-1表示错误
     */
    virtual int Output(const char* buffer, int size) = 0;
};

// =====================================================================
// KCP封装类
// =====================================================================

/**
 * @brief KCP协议封装类
 * 
 * 提供KCP协议的简单C++接口。
 * 
 * 使用示例：
 * @code
 *     KCPWrapper kcp(conv, &userData);
 *     kcp.SetConfig(GetNodelayConfig());
 *     kcp.Update();
 *     
 *     // 发送数据
 *     kcp.Send(data, dataSize);
 *     
 *     // 接收数据
 *     char buffer[1400];
 *     int n = kcp.Recv(buffer, sizeof(buffer));
 * @endcode
 */
class KCPWrapper {
public:
    /**
     * @brief 构造函数
     * @param conv 会话ID
     * @param output 输出接口
     */
    explicit KCPWrapper(uint32_t conv, IKCPOutput* output);

    /**
     * @brief 析构函数
     */
    ~KCPWrapper();

    // 禁止拷贝
    KCPWrapper(const KCPWrapper&) = delete;
    KCPWrapper& operator=(const KCPWrapper&) = delete;

    /**
     * @brief 设置配置
     * @param config 配置结构体
     */
    void SetConfig(const KCPConfig& config);

    /**
     * @brief 更新KCP状态
     * @param currentTick 当前时间（毫秒）
     * 
     * 必须在每个时间步调用，以处理重传和拥塞控制。
     */
    void Update(uint32_t currentTick);

    /**
     * @brief 发送数据
     * @param data 数据缓冲区
     * @param size 数据大小
     * @return 0表示成功，-1表示错误
     */
    int Send(const void* data, int size);

    /**
     * @brief 接收数据
     * @param buffer 输出缓冲区
     * @param size 缓冲区大小
     * @return 接收的字节数，-1表示错误，0表示没有数据
     */
    int Recv(void* buffer, int size);

    /**
     * @brief 处理传入的KCP包
     * @param data 包数据
     * @param size 包大小
     */
    void Input(const void* data, int size);

    /**
     * @brief 检查发送窗口是否还有空间
     * @return 如果还有空间返回true
     */
    bool CanSend() const;

    /**
     * @brief 获取待发送的数据量
     * @return 字节数
     */
    int SendQueueSize() const;

    /**
     * @brief 获取待接收的数据量
     * @return 字节数
     */
    int RecvQueueSize() const;

    /**
     * @brief 重置KCP状态
     */
    void Reset();

    /**
     * @brief 获取往返时间估计
     * @return RTT（毫秒）
     */
    int GetRTT() const;

    /**
     * @brief 获取拥塞窗口大小
     * @return cwnd
     */
    int GetCwnd() const;

private:
    void* kcp_;
    IKCPOutput* output_;
    bool initialized_;
};

} // namespace PhysicsSync",
