// ======== ================== ==== ========= ============================
// PhysicsObjectState 测试
// ======== ================== ==== ========= ============================

TEST(PhysicsObjectStateTest, DefaultConstruction) {
    PhysicsObjectState state;
    EXPECT_EQ(state.objectId, 0);
    EXPECT_EQ(state.flags, 0);
    EXPECT_EQ(state.version, 0);
